import numpy as np

class Perceptron:
 def __init__(self, learning_rate=0.01, num_iterations=1000):
 self.learning_rate = learning_rate
 self.num_iterations = num_iterations
 self.weights = None

 def fit(self, X, y):
 num_samples, num_features = X.shape
 self.weights = np.zeros(num_features)
 for _ in range(self.num_iterations):
 for idx, x_i in enumerate(X):
 prediction = np.dot(x_i, self.weights)
 if prediction * y[idx] < 0:
 self.weights += self.learning_rate * y[idx] * x_i

 def predict(self, X):
 predictions = np.dot(X, self.weights)
 return np.sign(predictions)

#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define LEARNING_RATE 0.01
#define NUM_ITERATIONS 1000

void perceptron(double *X, double *y, int num_samples, int num_features) {
 double *weights = (double *)malloc(num_features * sizeof(double));
 for (int i = 0; i < num_features; i++) {
 weights[i] = 0.0;
 }
 for (int iter = 0; iter < NUM_ITERATIONS; iter++) {
 for (int i = 0; i < num_samples; i++) {
 double prediction = 0.0;
 for (int j = 0; j < num_features; j++) {
 prediction += X[i * num_features + j] * weights[j];
 }
 if (prediction * y[i] < 0) {
 for (int j = 0; j < num_features; j++) {
 weights[j] += LEARNING_RATE * y[i] * X[i * num_features + j];
 }
 }
 }
 }
 free(weights);
}
